// ============================================================
// Code Node 1: Input-Validierung & Sanitisierung
// ============================================================

const body = $input.first().json.body || $input.first().json;

const session_id = body.session_id || '';
const raw_message = body.message || '';

// --- 1. session_id validieren (UUID v4 Format, nur Logging) ---
const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
if (!UUID_REGEX.test(session_id)) {
  return [
    {
      json: {
        valid: false,
        error: 'Ungültige Session-ID.',
        session_id: 'invalid'
      }
    }
  ];
}

// --- 2. Nachricht prüfen: leer? ---
if (!raw_message || raw_message.trim().length === 0) {
  return [
    {
      json: {
        valid: false,
        error: 'Nachricht darf nicht leer sein.',
        session_id
      }
    }
  ];
}

// --- 3. Länge prüfen: max 500 Zeichen ---
if (raw_message.length > 500) {
  return [
    {
      json: {
        valid: false,
        error: 'Nachricht zu lang (max. 500 Zeichen).',
        session_id
      }
    }
  ];
}

// --- 4. HTML-Tags entfernen (Strip) ---
let sanitized = raw_message.replace(/<[^>]*>/g, '');

// --- 5. SQL-Injection Muster entfernen (Basisschutz) ---
sanitized = sanitized.replace(/(['"\\;]|--|\/\*|\*\/|\bDROP\b|\bSELECT\b|\bINSERT\b|\bDELETE\b|\bUPDATE\b|\bEXEC\b|\bUNION\b)/gi, '');

// --- 6. Steuerzeichen entfernen ---
sanitized = sanitized.replace(/[\x00-\x1F\x7F]/g, ' ').trim();

// --- 7. Ergebnis ---
return [
  {
    json: {
      valid: true,
      message: sanitized,
      session_id,
      timestamp: new Date().toISOString()
    }
  }
];

// ============================================================
// Code Node 2: Gesprächspfad-Klassifikation (6 Kategorien)
// ============================================================

const message = ($json.message || '').toLowerCase();

// Keyword-Sets je Kategorie
const patterns = {
  NIS2_QUESTION: [
    'nis2', 'nis 2', 'netzwerk- und informationssicherheit', 'kritische infrastruktur',
    'kritis', 'richtlinie', 'betrifft mich', 'muss ich', 'bin ich betroffen',
    'compliance', 'pflicht', 'bsig', '§38', 'informationssicherheit'
  ],
  COST_QUESTION: [
    'kostet', 'kosten', 'schaden', 'schäden', 'finanziell', 'verlust', 'verluste',
    'bußgeld', 'strafe', 'teuer', 'preis', 'ausgaben', 'budget', 'wie viel',
    'wieviel', 'million', 'euro', 'angriff kostet', 'cyberangriff kosten'
  ],
  PHISHING_QUESTION: [
    'phishing', 'verdächtig', 'verdächtige', 'e-mail', 'email', 'spam', 'betrug',
    'link', 'anhang', 'attachment', 'absender', 'fake', 'gefälscht', 'klicken',
    'klick', 'passwort eingeben', 'bankdaten', 'dringend', 'sofortiger handlungsbedarf',
    'soll ich öffnen', 'ist das sicher', 'smishing', 'vishing'
  ],
  SECURITY_CHECK: [
    'wie sicher', 'sicherheit prüfen', 'security check', 'meinen server', 'meine website',
    'meine domain', 'ssl', 'tls', 'zertifikat', 'dmarc', 'spf', 'dkim', 'patch',
    'patches', 'backup', 'sicherheitscheck', 'schwachstellen', 'scan', 'prüfen',
    'sicher bin', 'wie gut', 'sicherheitsniveau'
  ],
  PRODUCT_INFO: [
    'kyberguard', 'was ist kyber', 'euer produkt', 'ihr produkt', 'wie funktioniert',
    'features', 'funktionen', 'preise', 'abo', 'abonnement', 'pro plan', 'business plan',
    'enterprise', 'demo', 'testen', 'trial', '34,99', '99,99', 'registrieren',
    'anmelden', 'kostenlos testen'
  ]
};

// Scoring-Funktion
function classify(msg, patternMap) {
  const scores = {};
  for (const [category, keywords] of Object.entries(patternMap)) {
    scores[category] = keywords.filter(kw => msg.includes(kw)).length;
  }
  // Beste Kategorie
  const best = Object.entries(scores).sort((a, b) => b[1] - a[1])[0];
  return best[1] > 0 ? best[0] : 'OTHER';
}

const category = classify(message, patterns);

return [
  {
    json: {
      ...$json,
      category
    }
  }
];

// ============================================================
// Code Node 3: Anthropic-Antwort extrahieren + Response bauen
// ============================================================

const inputData = $input.first().json;

// Anthropic gibt content[0].text zurück
let aiText = '';
try {
  aiText = inputData.content[0].text || '';
} catch (e) {
  aiText = 'Entschuldigung, ich konnte Ihre Anfrage gerade nicht verarbeiten. Bitte versuchen Sie es erneut.';
}

// Kategorie aus vorherigem Knoten holen
// (wird via $('Kategorie erkennen').first().json weitergegeben)
const category = $('Kategorie erkennen').first().json.category || 'OTHER';

return [
  {
    json: {
      message: aiText.trim(),
      category: category,
      cta: {
        text: 'Kostenlos testen',
        url: 'https://kyberguard.de/register'
      }
    }
  }
];

